mapper.select:
SELECT COUNT(*)
FROM TBL_WORK
WHERE TO_CHAR(WORK_START,'YYYY-MM-DD') = #{workStart}
  AND WORK_NAME = #{workName}

mapper.update:
UPDATE TBL_WORK
SET WORK_END = CURRENT_TIMESTAMP
WHERE TO_CHAR(WORK_START,'YYYY-MM-DD') = #{workStart}
    AND WORK_NAME = #{workName}

mapper.select:
SELECT COUNT(*)
FROM TBL_WORK
WHERE TO_CHAR(WORK_END,'YYYY-MM-DD') = #{workEnd}
    AND WORK_NAME = #{workName}
